import { Injectable } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';
import { environment } from 'src/environments/environment';
import { Vehicule, VehiculeFilters } from '@/models/vehicule.model';

export interface ApiResponse<T> {
  success: boolean;
  message: string;
  data: T;
}

@Injectable({ providedIn: 'root' })
export class VehiculeService {
  private readonly baseUrl = environment.apiUrl;

  constructor(private http: HttpClient) {}

  getVehicules(filters?: VehiculeFilters): Observable<ApiResponse<Vehicule[]>> {
    let params = new HttpParams();
    if (filters?.search) params = params.set('search', filters.search);
    if (filters?.per_page) params = params.set('per_page', String(filters.per_page));
    return this.http.get<ApiResponse<Vehicule[]>>(`${this.baseUrl}/vehicules`, { params });
  }

  getVehicule(id: number): Observable<ApiResponse<Vehicule>> {
    return this.http.get<ApiResponse<Vehicule>>(`${this.baseUrl}/vehicules/${id}`);
  }

  /** Création one-shot : véhicule + propriétaire + livreur + commission en une seule requête */
  createOneShot(formData: FormData): Observable<ApiResponse<Vehicule>> {
    return this.http.post<ApiResponse<Vehicule>>(
      `${this.baseUrl}/livraisons/one-shot`,
      formData
    );
  }
}
